#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int x, y;
        scanf("%d %d", &x, &y);
        printf("%d\n", 10 * x + y);
    }
    return 0;
}

